sql:
SELECT year, median_house_price
FROM housing_data
WHERE borough_id = 0;

SELECT num_parks, num_cafes
FROM amenities
WHERE year = 2020 AND borough_id = 1;

SELECT year, active_businesses, unemployment_rate
FROM economic_data
WHERE borough_id = 1;

SELECT borough_id, AVG(median_house_price) AS average_median_house_price
FROM housing_data
GROUP BY borough_id;

SELECT borough_id, COUNT(*) AS total_amenities
FROM amenities
GROUP BY borough_id;

external_knowledge:
- Above-average growth rate refers to a population increase higher than the average increase across all boroughs; 
- The last five years are determined by the years available in the population data, with the most recent year being the maximum year in the population data table; 
- Key statistics include average gross annual pay, unemployment rate, crime rate per thousand population, median house price, and the number of parks and hotels; 
- Top-performing boroughs refer to those with the highest average gross annual pay.

sql:
SELECT name
FROM boroughs
WHERE population_density > (SELECT AVG(population_density) FROM boroughs);

SELECT median_house_price
FROM housing_data
WHERE borough_id = 1 AND year = 2017;

SELECT unemployment_rate, gross_annual_pay
FROM economic_data
WHERE borough_id = 0 AND year = 0;
